        }
    }
    printf("\n二：");
    for(i=0;i<15;i++)
    {
        if(T[i].id==1)
        {
            printf("%s,",T[i].name);
        }
    }
    printf("\n三：");
    for(i=0;i<15;i++)
    {
        if(T[i].id==2)
        {
            printf("%s",T[i].name);
        }
    }

}

